/**
 * @param {number[][]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {
    // Helper function to check if a point exists in a set of points
    const pointToString = (p) => p.join(',');

    // Initialize the set of known points (Generation 0)
    let currentPointsSet = new Set();
    for (const p of points) {
        currentPointsSet.add(pointToString(p));
    }

    // Check Generation 0
    const targetStr = pointToString(target);
    if (currentPointsSet.has(targetStr)) {
        return 0;
    }

    // If there is only one initial point, no new points can be generated
    if (points.length <= 1) {
        return -1;
    }

    let k = 0;
    let previousPointsArray = points;

    // We continue generation until the target is found or no new points can be generated
    while (true) {
        k++;
        const newPoints = new Set();
        const prevPointsArray = Array.from(currentPointsSet).map(str => str.split(',').map(Number));

        // Iterate over all pairs of different points from all generations up to k-1
        const N = prevPointsArray.length;

        // The rule is: "Consider from Generation 0 to Generation k-1 all extracted pairs of two *different* points."
        // The set of available points for generation k is the union of all points from G0 to G(k-1).
        // currentPointsSet already contains all points up to G(k-1).

        // Generate new points (Generation k)
        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                const p1 = prevPointsArray[i];
                const p2 = prevPointsArray[j];

                // Check if points are different coordinates (as per problem statement: "two different points")
                // Since we iterate j > i over a set of unique coordinates, p1 and p2 are guaranteed to be different points in the set.
                // However, the problem states: "two different points" meaning they must have different (x, y, z) coordinates.
                // Since currentPointsSet stores unique coordinate vectors, p1 !== p2 implies they are different points with different coordinates.

                // Calculate c = [floor((x1 + x2) / 2), floor((y1 + y2) / 2), floor((z1 + z2) / 2)]
                const c = [
                    Math.floor((p1[0] + p2[0]) / 2),
                    Math.floor((p1[1] + p2[1]) / 2),
                    Math.floor((p1[2] + p2[2]) / 2)
                ];

                const cStr = pointToString(c);

                // Only add if it's truly a new point not yet found (optimization/correctness)
                if (!currentPointsSet.has(cStr)) {
                    newPoints.add(cStr);
                }
            }
        }

        // Check if the target was generated in this step
        if (newPoints.has(targetStr)) {
            return k;
        }

        // Update the set of known points for the next iteration
        if (newPoints.size === 0) {
            // No new points were generated, target cannot be reached
            return -1;
        }

        for (const pStr of newPoints) {
            currentPointsSet.add(pStr);
        }
    }
}

